47	func (f *CommandFactory) newAgentMetricsTierSuccessCommand() *cobra.Command {
48		cmd := &cobra.Command{
49			Use:   "tier-success",
50			Short: "Report success rate per harness/model tier from execution evidence",
51			Long: `Scan .ddx/executions/*/result.json and aggregate execution outcomes
52	into per-tier success rates. A tier is identified by harness alone when the
53	result has no model field, or by harness/model when a concrete model is
54	recorded. Success is defined as outcome == "task_succeeded".`,
55			Args: cobra.NoArgs,
56			RunE: func(cmd *cobra.Command, args []string) error {
57				lastN, _ := cmd.Flags().GetInt("last")
58				jsonOut, _ := cmd.Flags().GetBool("json")
59	
60				rows, err := computeTierSuccess(f.WorkingDir, lastN)
61				if err != nil {
62					return err
63				}
64	
65				if jsonOut {
66					enc := json.NewEncoder(cmd.OutOrStdout())
67					enc.SetIndent("", "  ")
68					return enc.Encode(rows)
69				}
70				return renderTierSuccessTable(cmd, rows)
71			},
72		}
73		cmd.Flags().Int("last", 0, "Limit to most recent N attempts (0 = all)")
74		cmd.Flags().Bool("json", false, "Output JSON")
75		return cmd
76	}
