78	// computeTierSuccess scans .ddx/executions/*/result.json under workingDir and
79	// returns per-tier aggregates. When lastN > 0, only the most recent lastN
80	// attempts (sorted by attempt directory name, which is a sortable timestamp)
81	// are considered.
82	func computeTierSuccess(workingDir string, lastN int) ([]tierSuccessRow, error) {
83		execRoot := filepath.Join(workingDir, ".ddx", "executions")
84		entries, err := os.ReadDir(execRoot)
85		if err != nil {
86			if os.IsNotExist(err) {
87				return []tierSuccessRow{}, nil
88			}
89			return nil, fmt.Errorf("read executions dir: %w", err)
90		}
91	
92		names := make([]string, 0, len(entries))
93		for _, entry := range entries {
94			if entry.IsDir() {
95				names = append(names, entry.Name())
96			}
97		}
98		// Directory names are sortable timestamps (YYYYMMDDTHHMMSS-<hash>), so
99		// lexicographic sort is chronological.
100		sort.Strings(names)
101	
102		// First pass: read and keep only usable results, preserving chronological
103		// order. --last N then picks the most recent N usable attempts so that
104		// malformed or missing files never hide a valid recent attempt.
105		type loadedResult struct {
106			harness     string
107			model       string
108			outcome     string
109			failureMode string
110			costUSD     float64
111			durMS       int
112		}
113		loaded := make([]loadedResult, 0, len(names))
114		for _, name := range names {
115			resultPath := filepath.Join(execRoot, name, "result.json")
116			raw, err := os.ReadFile(resultPath)
117			if err != nil {
118				continue
119			}
120			var res agent.ExecuteBeadResult
121			if err := json.Unmarshal(raw, &res); err != nil {
122				continue
123			}
124			if res.Harness == "" {
125				continue
126			}
127			loaded = append(loaded, loadedResult{
128				harness:     res.Harness,
129				model:       res.Model,
130				outcome:     res.Outcome,
131				failureMode: res.FailureMode,
132				costUSD:     res.CostUSD,
133				durMS:       res.DurationMS,
134			})
135		}
136		if lastN > 0 && len(loaded) > lastN {
137			loaded = loaded[len(loaded)-lastN:]
138		}
139	
140		type agg struct {
141			harness          string
142			model            string
143			attempts         int
144			successes        int
145			totalCostUSD     float64
146			wastedCostUSD    float64
147			effectiveCostUSD float64
148			totalDurMS       float64
149			failureModes     map[string]int
150		}
151		byTier := map[string]*agg{}
152		order := []string{}
153	
154		for _, res := range loaded {
155			tier := tierKey(res.harness, res.model)
156			a, ok := byTier[tier]
157			if !ok {
158				a = &agg{harness: res.harness, model: res.model, failureModes: map[string]int{}}
159				byTier[tier] = a
160				order = append(order, tier)
161			}
162			a.attempts++
163			if res.outcome == "task_succeeded" {
164				a.successes++
165				a.effectiveCostUSD += res.costUSD
166			} else {
167				a.wastedCostUSD += res.costUSD
168			}
169			if res.failureMode != "" {
170				a.failureModes[res.failureMode]++
171			}
172			a.totalCostUSD += res.costUSD
173			a.totalDurMS += float64(res.durMS)
174		}
175	
176		rows := make([]tierSuccessRow, 0, len(order))
177		for _, tier := range order {
178			a := byTier[tier]
179			row := tierSuccessRow{
180				Tier:             tier,
181				Harness:          a.harness,
182				Model:            a.model,
183				Attempts:         a.attempts,
184				Successes:        a.successes,
185				WastedCostUSD:    a.wastedCostUSD,
186				EffectiveCostUSD: a.effectiveCostUSD,
187			}
188			if a.attempts > 0 {
189				row.SuccessRate = float64(a.successes) / float64(a.attempts)
190				row.AvgCostUSD = a.totalCostUSD / float64(a.attempts)
191				row.AvgDurationMS = a.totalDurMS / float64(a.attempts)
192			}
193			if len(a.failureModes) > 0 {
194				row.FailureModes = a.failureModes
195			}
196			rows = append(rows, row)
197		}
198		sort.Slice(rows, func(i, j int) bool { return rows[i].Tier < rows[j].Tier })
199		return rows, nil
200	}
201	
202	func tierKey(harness, model string) string {
203		if model == "" {
204			return harness
205		}
206		return harness + "/" + model
207	}
