209	func renderTierSuccessTable(cmd *cobra.Command, rows []tierSuccessRow) error {
210		out := cmd.OutOrStdout()
211		fmt.Fprintf(out, "%-40s  %8s  %9s  %12s  %12s  %14s  %14s  %14s  %s\n",
212			"TIER", "ATTEMPTS", "SUCCESSES", "SUCCESS_RATE", "AVG_COST_USD", "WASTED_COST", "EFFECTIVE_COST", "AVG_DURATION_MS", "FAILURE_MODES")
213		for _, r := range rows {
214			fmt.Fprintf(out, "%-40s  %8d  %9d  %12s  %12s  %14s  %14s  %14.1f  %s\n",
215				truncateTier(r.Tier, 40),
216				r.Attempts,
217				r.Successes,
218				fmt.Sprintf("%.3f", r.SuccessRate),
219				fmt.Sprintf("%.4f", r.AvgCostUSD),
220				fmt.Sprintf("%.4f", r.WastedCostUSD),
221				fmt.Sprintf("%.4f", r.EffectiveCostUSD),
222				r.AvgDurationMS,
223				formatFailureModes(r.FailureModes),
224			)
225		}
226		return nil
227	}
228	
229	// formatFailureModes renders a failure-mode breakdown as a stable, sorted
230	// "mode=count,mode=count" string. Returns "-" when no failure modes were
231	// recorded so the column is never blank.
232	func formatFailureModes(modes map[string]int) string {
233		if len(modes) == 0 {
234			return "-"
235		}
236		keys := make([]string, 0, len(modes))
237		for k := range modes {
238			keys = append(keys, k)
239		}
240		sort.Strings(keys)
241		parts := make([]string, 0, len(keys))
242		for _, k := range keys {
243			parts = append(parts, fmt.Sprintf("%s=%d", k, modes[k]))
244		}
245		return strings.Join(parts, ",")
246	}
247	
248	func truncateTier(s string, max int) string {
249		if len(s) <= max {
250			return s
251		}
252		const ellipsis = "…"
253		if max <= len(ellipsis) {
254			return strings.Repeat(".", max)
255		}
256		return s[:max-len(ellipsis)] + ellipsis
257	}
