259	// reviewOutcomesRow is one row of the review-outcomes report, aggregating
260	// post-merge review verdicts per originating execution tier.
261	type reviewOutcomesRow struct {
262		Tier         string  `json:"tier"`
263		Harness      string  `json:"harness"`
264		Model        string  `json:"model,omitempty"`
265		Reviews      int     `json:"reviews"`
266		Approvals    int     `json:"approvals"`
267		Rejections   int     `json:"rejections"`
268		ApprovalRate float64 `json:"approval_rate"`
269	}
