271	func (f *CommandFactory) newAgentMetricsReviewOutcomesCommand() *cobra.Command {
272		cmd := &cobra.Command{
273			Use:   "review-outcomes",
274			Short: "Report post-merge review verdicts per originating tier",
275			Long: `Scan kind:review evidence events on beads and aggregate review
276	verdicts (approve, approve_with_edits, reject) per originating harness/model
277	tier. The originating tier is derived from the most recent kind:routing
278	evidence event that precedes each review on the same bead — that is the
279	provider/model that produced the work being reviewed.`,
280			Args: cobra.NoArgs,
281			RunE: func(cmd *cobra.Command, args []string) error {
282				jsonOut, _ := cmd.Flags().GetBool("json")
283	
284				rows, err := computeReviewOutcomes(f.WorkingDir)
285				if err != nil {
286					return err
287				}
288	
289				if jsonOut {
290					enc := json.NewEncoder(cmd.OutOrStdout())
291					enc.SetIndent("", "  ")
292					return enc.Encode(rows)
293				}
294				return renderReviewOutcomesTable(cmd, rows)
295			},
296		}
297		cmd.Flags().Bool("json", false, "Output JSON")
298		return cmd
299	}
