301	// reviewVerdictCategory normalises a kind:review event summary into one of
302	// "approve", "approve_with_edits", "reject", or "" when it cannot be
303	// classified. Matching is case-insensitive and tolerates the canonical
304	// verdict names used by the reviewer (APPROVE / REQUEST_CHANGES / BLOCK)
305	// as well as their generic equivalents.
306	func reviewVerdictCategory(summary string) string {
307		s := strings.ToUpper(strings.TrimSpace(summary))
308		switch s {
309		case "APPROVE":
310			return "approve"
311		case "APPROVE_WITH_EDITS", "REQUEST_CHANGES":
312			return "approve_with_edits"
313		case "REJECT", "BLOCK":
314			return "reject"
315		}
316		return ""
317	}
318	
319	// computeReviewOutcomes scans every bead in workingDir/.ddx, attributes each
320	// kind:review event to the most recent kind:routing event that precedes it on
321	// the same bead, and aggregates per-tier counts of approvals vs rejections.
322	// Reviews on beads without any preceding routing event are bucketed under an
323	// "unknown" tier so they are surfaced rather than silently dropped.
324	func computeReviewOutcomes(workingDir string) ([]reviewOutcomesRow, error) {
325		store := bead.NewStore(filepath.Join(workingDir, ".ddx"))
326		beads, err := store.ReadAll()
327		if err != nil {
328			return nil, fmt.Errorf("read beads: %w", err)
329		}
330	
331		type agg struct {
332			harness    string
333			model      string
334			reviews    int
335			approvals  int
336			rejections int
337		}
338		byTier := map[string]*agg{}
339		order := []string{}
340	
341		for _, b := range beads {
342			events := allBeadEventsFromExtra(b.Extra)
343			// Walk events in chronological order, tracking the most recent
344			// routing decision so each review is attributed to the tier that
345			// produced the work under review.
346			sort.SliceStable(events, func(i, j int) bool {
347				return events[i].CreatedAt.Before(events[j].CreatedAt)
348			})
349	
350			var curHarness, curModel string
351			haveRouting := false
352			for _, e := range events {
353				switch e.Kind {
354				case "routing":
355					if h, m, ok := parseRoutingHarnessModel(e); ok {
356						curHarness = h
357						curModel = m
358						haveRouting = true
359					}
360				case "review":
361					cat := reviewVerdictCategory(e.Summary)
362					if cat == "" {
363						continue
364					}
365					harness, model := curHarness, curModel
366					if !haveRouting {
367						harness, model = "unknown", ""
368					}
369					tier := tierKey(harness, model)
370					a, ok := byTier[tier]
371					if !ok {
372						a = &agg{harness: harness, model: model}
373						byTier[tier] = a
374						order = append(order, tier)
375					}
376					a.reviews++
377					switch cat {
378					case "approve":
379						a.approvals++
380					case "approve_with_edits", "reject":
381						a.rejections++
382					}
383				}
384			}
385		}
386	
387		rows := make([]reviewOutcomesRow, 0, len(order))
388		for _, tier := range order {
389			a := byTier[tier]
390			row := reviewOutcomesRow{
391				Tier:       tier,
392				Harness:    a.harness,
393				Model:      a.model,
394				Reviews:    a.reviews,
395				Approvals:  a.approvals,
396				Rejections: a.rejections,
397			}
398			if a.reviews > 0 {
399				row.ApprovalRate = float64(a.approvals) / float64(a.reviews)
400			}
401			rows = append(rows, row)
402		}
403		sort.Slice(rows, func(i, j int) bool { return rows[i].Tier < rows[j].Tier })
404		return rows, nil
405	}
406	
407	// allBeadEventsFromExtra returns every BeadEvent stored on a bead, regardless
408	// of kind. The route-status command has a routing-only extractor; here we
409	// need both routing and review events so we walk Extra["events"] directly.
410	func allBeadEventsFromExtra(extra map[string]any) []bead.BeadEvent {
411		if extra == nil {
412			return nil
413		}
414		raw, ok := extra["events"]
415		if !ok {
416			return nil
417		}
418		items, ok := raw.([]any)
419		if !ok {
420			return nil
421		}
422		out := make([]bead.BeadEvent, 0, len(items))
423		for _, item := range items {
424			m, ok := item.(map[string]any)
425			if !ok {
426				continue
427			}
428			e := bead.BeadEvent{}
429			if v, ok := m["kind"].(string); ok {
430				e.Kind = v
431			}
432			if v, ok := m["summary"].(string); ok {
433				e.Summary = v
434			}
435			if v, ok := m["body"].(string); ok {
436				e.Body = v
437			}
438			if v, ok := m["actor"].(string); ok {
439				e.Actor = v
440			}
441			if v, ok := m["source"].(string); ok {
442				e.Source = v
443			}
444			if v, ok := m["created_at"].(string); ok {
445				if t, err := time.Parse(time.RFC3339, v); err == nil {
446					e.CreatedAt = t
447				}
448			}
449			out = append(out, e)
450		}
451		return out
452	}
