454	// parseRoutingHarnessModel extracts (provider, model) from a kind:routing
455	// event body. Returns ok=false when the body cannot be parsed or carries no
456	// provider, since a tier without a provider is not a useful attribution.
457	func parseRoutingHarnessModel(e bead.BeadEvent) (string, string, bool) {
458		if e.Body == "" {
459			return "", "", false
460		}
461		var body struct {
462			ResolvedProvider string `json:"resolved_provider"`
463			ResolvedModel    string `json:"resolved_model"`
464		}
465		if err := json.Unmarshal([]byte(e.Body), &body); err != nil {
466			return "", "", false
467		}
468		if body.ResolvedProvider == "" {
469			return "", "", false
470		}
471		return body.ResolvedProvider, body.ResolvedModel, true
472	}
