490	// costEfficiencyRow is one row of the cost-efficiency report — total spend
491	// to close a single bead, with successful vs wasted (failed-attempt) cost
492	// broken out so escalation overhead is visible.
493	type costEfficiencyRow struct {
494		BeadID            string  `json:"bead_id"`
495		TotalAttempts     int     `json:"total_attempts"`
496		TotalCostUSD      float64 `json:"total_cost_usd"`
497		SuccessfulCostUSD float64 `json:"successful_cost_usd"`
498		WastedCostUSD     float64 `json:"wasted_cost_usd"`
499		FinalTier         string  `json:"final_tier"`
500		FinalHarness      string  `json:"final_harness"`
501	}
502	
503	func (f *CommandFactory) newAgentMetricsCostEfficiencyCommand() *cobra.Command {
504		cmd := &cobra.Command{
505			Use:   "cost-efficiency",
506			Short: "Report total cost to close each bead, including failed escalation attempts",
507			Long: `Scan .ddx/executions/*/result.json and aggregate cost per bead across
508	all attempts. The successful_cost_usd column sums attempts where outcome ==
509	"task_succeeded"; wasted_cost_usd sums attempts where outcome != "task_succeeded"
510	(failed runs that still consumed budget). final_tier and final_harness reflect
511	the most recent attempt for each bead, which is the tier that ultimately
512	closed it (or the last tier tried if it remains open).`,
513			Args: cobra.NoArgs,
514			RunE: func(cmd *cobra.Command, args []string) error {
515				lastN, _ := cmd.Flags().GetInt("last")
516				jsonOut, _ := cmd.Flags().GetBool("json")
517	
518				rows, err := computeCostEfficiency(f.WorkingDir, lastN)
519				if err != nil {
520					return err
521				}
522	
523				if jsonOut {
524					enc := json.NewEncoder(cmd.OutOrStdout())
525					enc.SetIndent("", "  ")
526					return enc.Encode(rows)
527				}
528				return renderCostEfficiencyTable(cmd, rows)
529			},
530		}
531		cmd.Flags().Int("last", 0, "Limit to beads touched in the most recent N executions (0 = all)")
532		cmd.Flags().Bool("json", false, "Output JSON")
533		return cmd
534	}
535	
536	// computeCostEfficiency scans .ddx/executions/*/result.json under workingDir
537	// and aggregates per-bead cost totals. When lastN > 0, the set of beads in
538	// the output is restricted to those with at least one attempt in the most
539	// recent N executions; for those beads, *all* historical attempts contribute
540	// to the totals so escalation chains are not artificially truncated.
541	func computeCostEfficiency(workingDir string, lastN int) ([]costEfficiencyRow, error) {
542		execRoot := filepath.Join(workingDir, ".ddx", "executions")
543		entries, err := os.ReadDir(execRoot)
544		if err != nil {
545			if os.IsNotExist(err) {
546				return []costEfficiencyRow{}, nil
547			}
548			return nil, fmt.Errorf("read executions dir: %w", err)
549		}
550	
551		names := make([]string, 0, len(entries))
552		for _, entry := range entries {
553			if entry.IsDir() {
554				names = append(names, entry.Name())
555			}
556		}
557		sort.Strings(names)
558	
559		type loadedAttempt struct {
560			beadID  string
561			harness string
562			model   string
563			outcome string
564			costUSD float64
565		}
566		loaded := make([]loadedAttempt, 0, len(names))
567		for _, name := range names {
568			resultPath := filepath.Join(execRoot, name, "result.json")
569			raw, err := os.ReadFile(resultPath)
570			if err != nil {
571				continue
572			}
573			var res agent.ExecuteBeadResult
574			if err := json.Unmarshal(raw, &res); err != nil {
575				continue
576			}
577			if res.BeadID == "" {
578				continue
579			}
580			loaded = append(loaded, loadedAttempt{
581				beadID:  res.BeadID,
582				harness: res.Harness,
583				model:   res.Model,
584				outcome: res.Outcome,
585				costUSD: res.CostUSD,
586			})
587		}
588	
589		// --last N: restrict the output set to beads touched by the most recent
590		// N usable attempts. All historical attempts for those beads still
591		// contribute to totals so escalation cost is visible.
592		var includeBead map[string]bool
593		if lastN > 0 && len(loaded) > 0 {
594			includeBead = map[string]bool{}
595			start := len(loaded) - lastN
596			if start < 0 {
597				start = 0
598			}
599			for _, a := range loaded[start:] {
600				includeBead[a.beadID] = true
601			}
602		}
603	
604		type agg struct {
605			beadID            string
606			totalAttempts     int
607			totalCostUSD      float64
608			successfulCostUSD float64
609			wastedCostUSD     float64
610			finalHarness      string
611			finalModel        string
612		}
613		byBead := map[string]*agg{}
614		order := []string{}
615	
616		for _, a := range loaded {
617			if includeBead != nil && !includeBead[a.beadID] {
618				continue
619			}
620			g, ok := byBead[a.beadID]
621			if !ok {
